'use client'
import { cn, useControllableSignal, useRovingFocus, useSignals } from '@cascivo/core'
import { forwardRef } from 'react'
import type { HTMLAttributes, ReactNode } from 'react'
import styles from './toggle-group.module.css'

export interface ToggleGroupItem {
  value: string
  label?: string
  icon?: ReactNode
  disabled?: boolean
}

export interface ToggleGroupProps extends Omit<
  HTMLAttributes<HTMLDivElement>,
  'onChange' | 'defaultValue'
> {
  type: 'single' | 'multiple'
  value?: string | string[]
  defaultValue?: string | string[]
  onValueChange?: (value: string | string[]) => void
  items: ToggleGroupItem[]
  orientation?: 'horizontal' | 'vertical'
  size?: 'sm' | 'md' | 'lg'
  disabled?: boolean
}

function isSelected(current: string | string[] | undefined, value: string): boolean {
  if (Array.isArray(current)) return current.includes(value)
  return current === value
}

export const ToggleGroup = forwardRef<HTMLDivElement, ToggleGroupProps>(function ToggleGroup(
  {
    type,
    value,
    defaultValue,
    onValueChange,
    items,
    orientation = 'horizontal',
    size = 'md',
    disabled = false,
    className,
    ...props
  },
  ref,
) {
  useSignals()
  const emptyDefault: string | string[] = type === 'multiple' ? [] : ''
  const [selected, setSelected] = useControllableSignal<string | string[]>({
    value,
    defaultValue: defaultValue ?? emptyDefault,
    onChange: onValueChange,
  })

  const roving = useRovingFocus({ orientation, loop: true })

  const toggle = (itemValue: string) => {
    const current = selected.value
    if (type === 'multiple') {
      const list = Array.isArray(current) ? current : []
      const next = list.includes(itemValue)
        ? list.filter((v) => v !== itemValue)
        : [...list, itemValue]
      setSelected(next)
    } else {
      // Single: clicking the active item clears it.
      setSelected(current === itemValue ? '' : itemValue)
    }
  }

  return (
    <div
      role={type === 'single' ? 'radiogroup' : 'group'}
      data-orientation={orientation}
      data-size={size}
      className={cn(styles['toggleGroup'], className as string | undefined)}
      ref={ref}
      {...props}
    >
      {items.map((item, index) => {
        const on = isSelected(selected.value, item.value)
        const itemDisabled = disabled || item.disabled
        const { ref: itemRef, ...rovingProps } = roving.getItemProps(index)
        const ariaProps =
          type === 'single'
            ? { role: 'radio' as const, 'aria-checked': on }
            : { 'aria-pressed': on }
        return (
          <button
            key={item.value}
            type="button"
            {...ariaProps}
            {...rovingProps}
            ref={itemRef}
            data-state={on ? 'on' : 'off'}
            disabled={itemDisabled}
            aria-label={item.icon && !item.label ? item.value : undefined}
            className={styles['item']}
            onClick={() => toggle(item.value)}
          >
            {item.icon}
            {item.label && <span>{item.label}</span>}
          </button>
        )
      })}
    </div>
  )
})

@layer cascivo.component {
  .toggleGroup {
    display: inline-flex;
    gap: var(--cascivo-space-1);
    padding: var(--cascivo-space-1);
    border-radius: var(--cascivo-radius-control);
    background-color: var(--cascivo-color-bg-subtle);

    &[data-orientation='horizontal'] {
      flex-direction: row;
    }

    &[data-orientation='vertical'] {
      flex-direction: column;
    }

    &[data-size='sm'] {
      --_item-h: var(--cascivo-control-height-sm);
      --_item-font: var(--cascivo-text-sm);
    }

    &[data-size='md'] {
      --_item-h: var(--cascivo-control-height-md);
      --_item-font: var(--cascivo-text-sm);
    }

    &[data-size='lg'] {
      --_item-h: var(--cascivo-control-height-lg);
      --_item-font: var(--cascivo-text-base);
    }
  }

  .item {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    gap: var(--cascivo-space-2);
    block-size: var(--_item-h, var(--cascivo-control-height-md));
    padding-inline: var(--cascivo-space-3);
    font-family: var(--cascivo-font-sans);
    font-size: var(--_item-font, var(--cascivo-text-sm));
    font-weight: var(--cascivo-font-medium);
    line-height: var(--cascivo-leading-none);
    white-space: nowrap;
    cursor: pointer;
    border: 1px solid transparent;
    border-radius: var(--cascivo-radius-item, var(--cascivo-radius-control));
    background-color: transparent;
    color: var(--cascivo-color-text);
    transition:
      background-color var(--cascivo-duration-150) var(--cascivo-ease-out),
      color var(--cascivo-duration-150) var(--cascivo-ease-out),
      box-shadow var(--cascivo-duration-150) var(--cascivo-ease-out);

    &:hover:not(:disabled) {
      background-color: var(--cascivo-color-surface);
    }

    &:focus-visible {
      outline: none;
      box-shadow: var(--cascivo-focus-ring);
    }

    &:disabled {
      opacity: 0.5;
      cursor: not-allowed;
    }

    &[data-state='on'] {
      background-color: var(--cascivo-color-surface);
      color: var(--cascivo-color-text);
      box-shadow: var(--cascivo-shadow-sm);
    }
  }
}

@media (forced-colors: active) {
  .item[data-state='on'] {
    border-color: Highlight;
  }

  .item:focus-visible {
    outline: 2px solid Highlight;
    outline-offset: 2px;
  }

  .item:disabled {
    color: GrayText;
  }
}
